-	// Parse semver
-	vParts := strings.Split(version, ".")
-	if len(vParts) < 2 {
-		return false
-	}
-
-	var major, minor int
-	if _, err := fmt.Sscanf(vParts[0], "%d", &major); err != nil {
-		return false
